// ConsoleServiceHandler is an implementation of the aura.v1.ConsoleService service.
type ConsoleServiceHandler interface {
	// 聚合摘要：舰队 / 任务 / 编排 / 录制的计数总览（Dashboard 首屏一次拉取）。
	GetDashboard(context.Context, *connect.Request[v1.GetDashboardRequest]) (*connect.Response[v1.GetDashboardResponse], error)
	// 任务历史分页读（dispatch 审计表消费面）；可按 node / 编排过滤（执行墙下钻）。
	ListTasks(context.Context, *connect.Request[v1.ListTasksRequest]) (*connect.Response[v1.ListTasksResponse], error)
	// 录制会话列表分页读（录放中心）。步序详情走既有 ControllerAdmin.GetTrace。
	ListTraces(context.Context, *connect.Request[v1.ListTracesRequest]) (*connect.Response[v1.ListTracesResponse], error)
	// 产物代理读：控制面代取对象存储字节，绕开浏览器不可达的内网 MinIO。
	GetArtifact(context.Context, *connect.Request[v1.GetArtifactRequest]) (*connect.Response[v1.GetArtifactResponse], error)
	// per-node 串行队列深度：console 截图轮询前查 >0 即跳帧，避免抢占 agent 任务队列（对抗 G，零 scheduler 改动）。
	GetQueueDepth(context.Context, *connect.Request[v1.GetQueueDepthRequest]) (*connect.Response[v1.GetQueueDepthResponse], error)
	// 并行编排触发：一条用例 fan-out 到 N 目标，gather 聚合 pass/fail 回报（部分失败标 partial 不熔断其余）。
	RunOrchestration(context.Context, *connect.Request[v1.RunOrchestrationRequest]) (*connect.Response[v1.RunOrchestrationResponse], error)
	// 编排详情钻取：orchestration_id → 汇总 + 关联 task_ids（执行墙下钻 → ListTasks 关联明细）。
	GetOrchestration(context.Context, *connect.Request[v1.GetOrchestrationRequest]) (*connect.Response[v1.GetOrchestrationResponse], error)
	// 编排历史分页读。
	ListOrchestrations(context.Context, *connect.Request[v1.ListOrchestrationsRequest]) (*connect.Response[v1.ListOrchestrationsResponse], error)
	// 舰队状态变更事件流（server-streaming）：registry 事件源推送，替代轮询。
	// aura.v1 首个 server-streaming RPC；浏览器 connect-web HTTP/1.1 即可消费（client/bidi 浏览器不适用，单推足够）。
	WatchFleet(context.Context, *connect.Request[v1.WatchFleetRequest], *connect.ServerStream[v1.FleetEvent]) error
	// 目标感知视觉融合触发（M9，additive）：仿 M6 StartTrace→GetTrace 的 submit→poll 形态。SubmitFusion 提交
	// 一次融合任务（a11y 元素树 + vision 检测框 target-aware fan-in）返 job_id 不阻塞。落 ConsoleService（fleet
	// 面，agent/编排/管理台消费）而非 node.proto ControllerAdmin，保 node.proto 字节级零动（Q1 定案）。
	SubmitFusion(context.Context, *connect.Request[v1.SubmitFusionRequest]) (*connect.Response[v1.SubmitFusionResponse], error)
	// 轮询融合 job 结果：status（running|done|failed）+ vision_invoked + 融合元素表 + result_key。
	GetFusionResult(context.Context, *connect.Request[v1.GetFusionResultRequest]) (*connect.Response[v1.GetFusionResultResponse], error)
	// console 读旁路（M10-P1，additive）：截图等只读工具绕 per-node 串行队列直达节点会话
	// （scheduler.DispatchReadOnly：只读白名单 + 录制租约豁免 + 不写审计），录制租约期与队列积压期
	// console 仍可看屏，任务队列时延不受读流量影响（SC-3① 读写分离）。错误语义沿 DispatchTool 响应
	// 形态：传输层错误合成同构错误信封，前端单一 envelope 解析路径不变。
	ReadNodeScreen(context.Context, *connect.Request[v1.ReadNodeScreenRequest]) (*connect.Response[v1.ReadNodeScreenResponse], error)
	// 设备接入 enrollment token 治理 + 节点元数据编辑（M12-P1，additive）。token 短期（default 1h）+ 限次
	// （default 1）+ 可吊销 + 权限最小（platform_scope 限定平台，Locked-1）；两副本共享 PG token（Locked-5）。
	// enroll 端点（节点安装收 CSR 签 per-node cert）走 REST bootstrap（TASK-006），非本 admin RPC——本组仅
	// console 管理台的 token 生命周期治理 + 节点元数据编辑面。
	GenerateEnrollToken(context.Context, *connect.Request[v1.GenerateEnrollTokenRequest]) (*connect.Response[v1.GenerateEnrollTokenResponse], error)
	RevokeEnrollToken(context.Context, *connect.Request[v1.RevokeEnrollTokenRequest]) (*connect.Response[v1.RevokeEnrollTokenResponse], error)
	RotateEnrollToken(context.Context, *connect.Request[v1.RotateEnrollTokenRequest]) (*connect.Response[v1.RotateEnrollTokenResponse], error)
	ListEnrollTokens(context.Context, *connect.Request[v1.ListEnrollTokensRequest]) (*connect.Response[v1.ListEnrollTokensResponse], error)
	// 节点元数据编辑（label/location 存 nodes 表持久；name 由节点自报不经此编辑）。
	UpdateNodeMeta(context.Context, *connect.Request[v1.UpdateNodeMetaRequest]) (*connect.Response[v1.UpdateNodeMetaResponse], error)
	// 舰队治理：删除离线僵尸节点（M12-P1 追加，additive）。仅 offline 节点可删——transport 层查活跃会话，
	// 在线拒删返 E_NODE_ONLINE（防误删活跃节点）；删 nodes + node_certs 身份台账，不删 tasks/traces 历史
	// （node_id 关联的审计/录制行保留，仅注销身份）。删除成功广播 node_removed FleetEvent（WatchFleet 自动
	// 刷新）。长期离线（AURA_NODE_REAP_DAYS default 30d）由 registry 后台定时自动遗忘，本 RPC 是即时手动路径。
	DeleteNode(context.Context, *connect.Request[v1.DeleteNodeRequest]) (*connect.Response[v1.DeleteNodeResponse], error)
	// 录屏视频列表分页读（录屏回放页，M12-P1 追加，additive）。节点 start_recording/stop_recording 产的
	// MP4 录屏落 MinIO recordings/*.mp4；本 RPC 列举对象（key/node_id/size/created），视频字节经既有
	// GetArtifact 代理读（浏览器不可达内网 MinIO，控制面代取）。区别于 ListTraces（工具调用轨迹复演 QA，非视频）。
	ListRecordings(context.Context, *connect.Request[v1.ListRecordingsRequest]) (*connect.Response[v1.ListRecordingsResponse], error)
	// 吊销节点证书（M12-P1 追加，additive）：console「吊销证书」触发面（design §7）。标记 node_certs.revoked
	// + 清 nodes.cert_fp——节点持吊销 cert 反连即遭 RevocationMiddleware 403 拒（执行面 T06 已验）。配合
	// DeleteNode 舰队治理（吊销阻反连 + 删离线僵尸身份）。吊销=标记非删行（保留台账供审计）。
	RevokeNodeCert(context.Context, *connect.Request[v1.RevokeNodeCertRequest]) (*connect.Response[v1.RevokeNodeCertResponse], error)
	// 单任务详情钻取（批E，additive）：失败任务下钻查因——ListTasks 摘要行之外补终态回执 envelope /
	// 录制会话关联 / 终态时刻（tasks 表批E 富化列）。envelope 落库前已剥离内联截图（详情面看回执结构与
	// 错误码；逐步截图仍走 trace 卸桶路径），旧行（富化列上线前）三者为空。
	GetTask(context.Context, *connect.Request[v1.GetTaskRequest]) (*connect.Response[v1.GetTaskResponse], error)
	// ===== 直连 MCP agent 观测（M13，additive）=====
	// 外部 coding agent 直连节点 /mcp 的活动此前 console 完全不可见（区别于 ListTasks 的 controller
	// 转发审计路径）。节点 /mcp 观测中间件采集 → AgentActivity 反连帧 → controller 落库，本组三 RPC
	// 供 console「接入观测」页消费：概览统计（GetAgentObservability）+ 接入会话列表（ListAgentSessions）
	// + 调用流水分页（ListAgentCalls）。纯内存降级：未配置 PG 时 controller 以有界环形缓冲兜底近期活动。
	GetAgentObservability(context.Context, *connect.Request[v1.GetAgentObservabilityRequest]) (*connect.Response[v1.GetAgentObservabilityResponse], error)
	ListAgentSessions(context.Context, *connect.Request[v1.ListAgentSessionsRequest]) (*connect.Response[v1.ListAgentSessionsResponse], error)
	ListAgentCalls(context.Context, *connect.Request[v1.ListAgentCallsRequest]) (*connect.Response[v1.ListAgentCallsResponse], error)
}

